import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as s,o as d,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Додавання каналу GitHub Releases","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/github-releases.md","filePath":"uk-UA/upload/github-releases.md","lastUpdated":1781962217000}'),r={name:"uk-UA/upload/github-releases.md"};function l(n,e,c,p,h,b){return d(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="додавання-каналу-github-releases" tabindex="-1">Додавання каналу GitHub Releases <a class="header-anchor" href="#додавання-каналу-github-releases" aria-label="Permalink to &quot;Додавання каналу GitHub Releases&quot;">​</a></h1><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><p>Потрібні лише три речі:</p><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис GitHub</td><td>Для створення access token і володіння репозиторієм.</td></tr><tr><td>GitHub Access Token</td><td>ImgBed використовує його для доступу до GitHub API, створення releases і завантаження файлів.</td></tr><tr><td>Назва репозиторію</td><td>Можна ввести тільки назву репозиторію, наприклад <code>image</code>.</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-увіидіть-у-github-і-створіть-access-token" tabindex="-1">Крок 1. Увійдіть у GitHub і створіть Access Token <a class="header-anchor" href="#крок-1-увіидіть-у-github-і-створіть-access-token" aria-label="Permalink to &quot;Крок 1. Увійдіть у GitHub і створіть Access Token&quot;">​</a></h3><ol><li>Увійдіть у GitHub.</li><li>Натисніть свій аватар у правому верхньому куті й відкрийте <code>Settings</code>.</li><li>У лівій бічній панелі відкрийте <code>Developer settings</code>.</li><li>Відкрийте <code>Personal access tokens</code>.</li><li>Відкрийте <code>Tokens (classic)</code>.</li><li>Натисніть <code>Generate new token (classic)</code>.</li><li>Дайте token зрозумілу назву.</li><li>Виберіть дату закінчення дії відповідно до вашого підходу до обслуговування.</li><li>Виберіть scopes <code>repo</code> і <code>workflow</code>.</li><li>Одразу після створення скопіюйте й збережіть token.</li></ol><p><img src="'+t+'" alt="Додавання прав GitHub" loading="lazy"></p><h2 id="крок-2-заповніть-канал-github-releases-в-imgbed" tabindex="-1">Крок 2. Заповніть канал GitHub Releases в ImgBed <a class="header-anchor" href="#крок-2-заповніть-канал-github-releases-в-imgbed" aria-label="Permalink to &quot;Крок 2. Заповніть канал GitHub Releases в ImgBed&quot;">​</a></h2><p>Після вибору <code>GitHub Releases</code> у налаштуваннях завантаження заповніть поля так:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Назва на ваш вибір, наприклад <code>GitHubPrimary</code>.</td></tr><tr><td>Access Token</td><td>GitHub Personal Access Token, який ви щойно створили.</td></tr><tr><td>Repository name</td><td>Або коротка назва repo, наприклад <code>image</code>, або повний шлях на кшталт <code>username/image</code>.</td></tr><tr><td>Private repository</td><td>Увімкніть або вимкніть відповідно до ваших потреб.</td></tr><tr><td>Remark</td><td>Необов&#39;язково, наприклад <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Заповнення конфігурації GitHub-каналу" loading="lazy"></p><h2 id="крок-3-збережіть-канал" tabindex="-1">Крок 3. Збережіть канал <a class="header-anchor" href="#крок-3-збережіть-канал" aria-label="Permalink to &quot;Крок 3. Збережіть канал&quot;">​</a></h2><p>Після заповнення полів натисніть Save.</p><p>Система сама обробить такі деталі:</p><table tabindex="0"><thead><tr><th>Поведінка системи</th><th>Опис</th></tr></thead><tbody><tr><td>Коротка назва репозиторію</td><td>ImgBed визначає поточний обліковий запис GitHub і розгортає значення до повного шляху репозиторію.</td></tr><tr><td>Повний шлях репозиторію</td><td>ImgBed використовує шлях <code>username/repository</code> саме в тому вигляді, у якому його введено.</td></tr><tr><td>Перевірка репозиторію</td><td>Якщо використовується шлях поточного особистого акаунта, ImgBed автоматично створює репозиторій, коли його ще немає. Якщо повний шлях введено вручну, ImgBed використовує його напряму.</td></tr><tr><td>Публічний або приватний стан</td><td>Видимість репозиторію синхронізується відповідно до поточного перемикача.</td></tr></tbody></table><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><p>GitHub Releases працює так:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Увійти в GitHub</span></span>
<span class="line"><span>-&gt; Створити Access Token</span></span>
<span class="line"><span>-&gt; Повернутися до ImgBed і ввести token та назву репозиторію</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Якщо введено тільки назву repo, ImgBed автоматично додасть поточний username</span></span>
<span class="line"><span>-&gt; Якщо введено username/repo, ImgBed використає це як є</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення</span></span></code></pre></div>`,19)])])}const k=s(r,[["render",l]]);export{g as __pageData,k as default};
